function HomeTestimonials(){const reviews=[['Padmarao Parimala','Family pilgrimage','Everything was organized with patience and care. The journey felt comfortable from the first day to the last.'],['Sai Swetha','Group traveller','The hotels, food and guidance were beautifully coordinated. Our group returned with wonderful memories.'],['Santosh Satuluri','Kakani guest','A thoughtful team, smooth arrangements and friendly support throughout our journey.']];const [active,setActive]=useState(0);useEffect(()=>{const t=setInterval(()=>setActive(x=>(x+1)%reviews.length),4500);return()=>clearInterval(t)},[]);return <section className="testimonials"><div className="wrap testimonial-layout"><div><p className="eyebrow">Guest stories</p><h2>Travel remembered<br/>for how it felt.</h2><div className="testimonial-controls"><button onClick={()=>setActive((active+reviews.length-1)%reviews.length)} aria-label="Previous testimonial">←</button><span>{String(active+1).padStart(2,'0')} / {String(reviews.length).padStart(2,'0')}</span><button onClick={()=>setActive((active+1)%reviews.length)} aria-label="Next testimonial">→</button></div></div><AnimatePresence mode="wait"><motion.blockquote key={active} initial={{opacity:0,x:35}} animate={{opacity:1,x:0}} exit={{opacity:0,x:-20}}><div className="review-stars" aria-label="5 out of 5 stars">★★★★★</div><p>“{reviews[active][2]}”</p><footer><span className="avatar">{reviews[active][0].charAt(0)}</span><span><b>{reviews[active][0]}</b><small>{reviews[active][1]}</small></span></footer></motion.blockquote></AnimatePresence></div></section>}
function HomeJournal(){return <section className="journal wrap"><div className="journal-head"><div><p className="eyebrow">The pilgrimage journal</p><h2>Stories for the road</h2></div><a href="#blog">View all stories <ArrowRight/></a></div><div className="journal-grid"><motion.a href="#blog" className="journal-feature" whileHover={{y:-6}}><img loading="lazy" src={posts[0][3]} alt="Kedarnath pilgrimage landscape"/><div><span>{posts[0][1]} · 6 min read</span><h3>{posts[0][0]}</h3><p>Season, registration, route and preparation guidance for a peaceful Himalayan yatra.</p></div></motion.a><div className="journal-secondary">{posts.slice(1,4).map((p,i)=><motion.a href="#blog" whileHover={{x:6}} key={p[0]}><img loading="lazy" src={p[3]} alt=""/><div><span>{p[1]} · {i+4} min read</span><h3>{p[0]}</h3></div><ArrowRight/></motion.a>)}</div></div></section>}
function About() {
  return <><PageHero page="About Us" title="About Us" text="Our Journey. Our Purpose. Your Trust." bg={img.temple} /><section className="wrap story split"><div className="video-card tilt"><img src={img.chardham} /><button>▶</button></div><div><SectionTitle over="Our Story" title="A Tradition of Devotion and Excellence" /><p>Kakatiya Travels is dedicated to creating meaningful pilgrimage journeys that connect devotees with the divine across India. Every journey is planned with care, comfort and trust.</p><p>From ancient temples to sacred rivers, we handle the details so you can focus on your connection with the divine.</p><div className="icon-row">{features.slice(0,4).map(([a,,Icon]: any)=><span key={a}><Icon />{a}</span>)}</div></div></section><Stats /><section className="mission wrap"><Card title="Our Mission" text="To provide seamless, comfortable and spiritually enriching journeys that inspire devotion and create lifelong memories." /><div className="arch"><img src={img.temple} /></div><Card title="Our Vision" text="To be India's most trusted and preferred devotional travel partner, known for excellence, integrity and heartfelt service." /></section><section className="wrap"><SectionTitle over="Why Choose Kakatiya Travels" title="Travel with Confidence, Devotion and Care" /><FeatureGrid /><div className="leadership"><Team /><Commitment /></div></section></>
}
function DestinationsPage() {
  const [zone,setZone]=useState('All Destinations'), [query,setQuery]=useState(''), [season,setSeason]=useState('Any season'), [active,setActive]=useState(0)
  const filtered=destinationData.filter(d=>(zone==='All Destinations'||d.zone===zone)&&(season==='Any season'||d.best.toLowerCase().includes(season.toLowerCase()))&&`${d.name} ${d.region} ${d.places.join(' ')}`.toLowerCase().includes(query.toLowerCase()))
  const collections=[['Most Visited','Living traditions, celebrated darshan and India’s most beloved temple towns.',destinationData.slice(0,4)],['Himalayan Shrines','High-altitude sanctuaries where silence, courage and devotion meet.',destinationData.filter(d=>['Kedarnath','Badrinath','Vaishno Devi'].includes(d.name))],['Southern Temple Legacy','Monumental architecture, ancient rituals and sacred coastal journeys.',destinationData.filter(d=>d.zone==='South India')]] as const
  const circuits=[['01','Char Dham','Four Himalayan sanctuaries'],['02','Jyotirlinga','Sacred manifestations of Shiva'],['03','Pancha Bhoota','Five elemental temples'],['04','Pancha Dwaraka','The western Krishna trail'],['05','South India','A journey through temple heritage']]
  return <><section className="destinations-hero"><img src={img.dwarka} alt="Sacred temple landscape in India"/><div className="destination-mist"/><div className="diya-particles">{[...Array(12)].map((_,i)=><i style={{'--i':i} as React.CSSProperties} key={i}/>)}</div><div className="wrap destination-hero-copy"><motion.p initial={{opacity:0,y:18}} animate={{opacity:1,y:0}}>Journeys through sacred India</motion.p><motion.h1 initial={{opacity:0,y:35}} animate={{opacity:1,y:0}} transition={{duration:.8}}>Explore India’s<br/><em>Sacred Destinations</em></motion.h1><motion.span initial={{opacity:0}} animate={{opacity:1}} transition={{delay:.3}}>Discover timeless temples, divine traditions and unforgettable spiritual journeys.</motion.span><motion.div initial={{opacity:0,y:18}} animate={{opacity:1,y:0}} transition={{delay:.45}}><Button href="#destination-collections">Explore destinations</Button><Button href="#sacred-map" outline>View India map</Button></motion.div></div><a className="destination-scroll" href="#sacred-map"><span/>Discover</a></section><section id="sacred-map" className="sacred-map-section"><div className="wrap map-heading"><p>Sacred geography</p><h2>A country connected by devotion</h2><span>Choose a glowing marker to preview each pilgrimage. The golden path traces India’s celebrated sacred circuits.</span></div><div className="wrap sacred-map-layout"><div className="india-map"><div className="india-shape"/><svg viewBox="0 0 800 650" preserveAspectRatio="none" aria-hidden="true"><path d="M282 96 C372 140 478 126 518 205 S440 292 522 348 520 475 403 564"/></svg>{destinationData.map((d,i)=><button className={`map-marker marker-${i} ${active===i?'active':''}`} onMouseEnter={()=>setActive(i)} onFocus={()=>setActive(i)} onClick={()=>setActive(i)} aria-label={`Preview ${d.name}`} key={d.name}><span/><b>{d.name}</b></button>)}</div><AnimatePresence mode="wait"><motion.a href={`#destination/${slug(destinationData[active].name)}`} className="map-preview" key={active} initial={{opacity:0,x:20}} animate={{opacity:1,x:0}} exit={{opacity:0,x:-12}}><img src={destinationData[active].image}/><div><small>{destinationData[active].zone} · {destinationData[active].region}</small><h3>{destinationData[active].name}</h3><p>{destinationData[active].intro}</p><span><CalendarDays/>{destinationData[active].best}</span><span><Clock/>{destinationData[active].duration}</span><b>Explore sacred journey <ArrowRight/></b></div></motion.a></AnimatePresence></div></section><section className="destination-feature wrap"><motion.div initial={{opacity:0,scale:1.06}} whileInView={{opacity:1,scale:1}} viewport={{once:false,amount:.25}}><img src={img.tirupati}/></motion.div><motion.article initial={{opacity:0,y:36}} whileInView={{opacity:1,y:0}} viewport={{once:false,amount:.3}}><p>Featured pilgrimage · Andhra Pradesh</p><h2>Tirupati Balaji</h2><span>One of the world’s most visited pilgrimage destinations, where millions seek the blessings of Lord Venkateswara amid the forested Tirumala hills.</span><dl><div><dt>Temple significance</dt><dd>Lord Venkateswara</dd></div><div><dt>Best season</dt><dd>September to March</dd></div><div><dt>Ideal journey</dt><dd>3 Days / 2 Nights</dd></div></dl><Button href="#destination/tirupati-balaji">Explore sacred journey</Button></motion.article></section><section className="destination-filter-shell"><div className="destination-filter wrap"><label><span>Search</span><div><Search/><input value={query} onChange={e=>setQuery(e.target.value)} placeholder="Temple or destination"/></div></label><label><span>Region</span><select value={zone} onChange={e=>setZone(e.target.value)}>{['All Destinations','North India','South India','East India','West India','Central India'].map(x=><option key={x}>{x}</option>)}</select></label><label><span>Travel season</span><select value={season} onChange={e=>setSeason(e.target.value)}><option>Any season</option><option>October</option><option>March</option><option>May</option><option>September</option></select></label><div><Filter/><b>{filtered.length}</b><span>Sacred places</span></div></div></section><section id="destination-collections" className="destination-collections wrap"><div className="collection-head"><p>Curated journeys</p><h2>Discover India through sacred stories</h2></div>{query||zone!=='All Destinations'||season!=='Any season'?<div className="filtered-editorial">{filtered.map((d,i)=><DestinationStory d={d} index={i} key={d.name}/>)}</div>:collections.map(([title,text,items],collectionIndex)=><div className={`destination-collection collection-${collectionIndex}`} key={title}><header><span>0{collectionIndex+1}</span><div><h3>{title}</h3><p>{text}</p></div></header><div>{items.map((d,i)=><DestinationStory d={d} index={i} compact={collectionIndex>0} key={d.name}/>)}</div></div>)}{!filtered.length&&<div className="empty">No sacred destinations match these filters.</div>}</section><section className="pilgrimage-circuits"><div className="wrap"><div className="circuit-intro"><p>Sacred routes</p><h2>India’s timeless pilgrimage circuits</h2><span>Follow journeys shaped over centuries, connecting temples, landscapes and living traditions.</span></div><div className="circuit-line">{circuits.map(([n,name,text],i)=><motion.article initial={{opacity:0,y:25}} whileInView={{opacity:1,y:0}} viewport={{once:false}} transition={{delay:i*.08}} key={name}><b>{n}</b><span/><h3>{name}</h3><p>{text}</p></motion.article>)}</div></div></section><section className="destination-closing"><img src={img.water}/><div><p>Your pilgrimage, thoughtfully shaped</p><h2>Begin Your Spiritual Journey</h2><span>Speak with our travel experts for a journey designed around your devotion, comfort and pace.</span><div><Button href={tel}>Talk to expert</Button><Button href="#tour-packages" outline>Plan your tour</Button></div></div></section><Footer/></>
}

function DestinationStory({d,index,compact=false}:{d:Destination;index:number;compact?:boolean}) { return <motion.a href={`#destination/${slug(d.name)}`} className={`destination-story ${compact?'compact-story':''}`} initial={{opacity:0,y:45}} whileInView={{opacity:1,y:0}} viewport={{once:false,amount:.2}} transition={{duration:.65,delay:(index%3)*.08}}><img loading="lazy" src={d.image} alt={`${d.name} temple`}/><div><small><MapPin/>{d.region}</small><h3>{d.name}</h3><p>{d.intro}</p><ul><li><CalendarDays/>{d.best}</li><li><Clock/>{d.duration}</li></ul><b>Explore journey <ArrowRight/></b></div></motion.a> }
function PackagesPage() {
  const [place,setPlace]=useState('All Places'),[duration,setDuration]=useState('Any duration')
  const visible=packages.filter(p=>(place==='All Places'||p[1].includes(place)||p[0].includes(place))&&(duration==='Any duration'||p[2].startsWith(duration)))
  const collections=[['Char Dham & Himalayas','High-altitude journeys paced for reflection, comfort and careful acclimatization.',packages.filter(p=>/Dham|Kedarnath/.test(p[0]))],['Jyotirlinga & Shiva Trails','Ancient Shiva temples connected through thoughtfully coordinated routes.',packages.filter(p=>/Kashi|Jyotirlinga|Shirdi Nashik/.test(p[0]))],['Southern Temple Heritage','Architectural wonders, living rituals and sacred coastal landscapes.',packages.filter(p=>/South India|Tirupati|Madurai|Panchabhoota|Mantralayam/.test(p[0]))],['Shakti, Sai & Family Journeys','Comfortable, devotional itineraries suited to families and senior pilgrims.',packages.filter(p=>/Sai|Shirdi|Devi|Ayodhya/.test(`${p[0]} ${p[1]}`))]]
  const featured=packages[0]
  return <><section className="packages-hero"><img src={img.kashi} alt="Pilgrimage boats and temples at sunrise"/><div className="packages-hero-shade"/><div className="wrap packages-hero-copy"><motion.p initial={{opacity:0,y:16}} animate={{opacity:1,y:0}}>The Kakani pilgrimage collection</motion.p><motion.h1 initial={{opacity:0,y:35}} animate={{opacity:1,y:0}} transition={{duration:.8}}>Sacred Journeys,<br/><em>Designed With Care</em></motion.h1><motion.span initial={{opacity:0}} animate={{opacity:1}} transition={{delay:.3}}>Expertly planned temple journeys where every stay, transfer and darshan is considered around your comfort.</motion.span><Button href="#package-collection">Explore packages</Button></div><div className="packages-trust wrap"><span><b>50,000+</b>Pilgrims guided</span><span><b>15+</b>Years of care</span><span><b>24×7</b>Journey support</span><span><b>4.9</b>Guest rating</span></div></section><section className="signature-package wrap"><div className="signature-visual"><img src={featured[4]} alt={featured[0]}/><span>Signature journey</span></div><motion.article initial={{opacity:0,y:35}} whileInView={{opacity:1,y:0}} viewport={{once:false,amount:.3}}><p>Himalayan pilgrimage · {featured[2]}</p><h2>{featured[0]}</h2><span>Four sacred shrines, one considered route. Travel through Yamunotri, Gangotri, Kedarnath and Badrinath with dependable stays and on-journey assistance.</span><div className="signature-route">{['Haridwar','Yamunotri','Gangotri','Kedarnath','Badrinath'].map((x,i)=><div key={x}><b>{String(i+1).padStart(2,'0')}</b><span/><small>{x}</small></div>)}</div><div className="signature-services"><span><Hotel/>Selected stays</span><span><Bus/>Planned transport</span><span><Landmark/>Temple visits</span><span><Users/>Expert assistance</span></div><footer><div><small>From</small><strong>₹{featured[3]}</strong><span>per person*</span></div><Button href={`#package/${slug(featured[0])}`}>View journey</Button><Button href={wa} outline>Book now</Button></footer></motion.article></section><section className="package-discovery"><div className="package-filter wrap"><label><span>Destination</span><select value={place} onChange={e=>setPlace(e.target.value)}><option>All Places</option>{Array.from(new Set(destinationData.map(d=>d.name.split(' ')[0]))).map(x=><option key={x}>{x}</option>)}</select></label><label><span>Duration</span><select value={duration} onChange={e=>setDuration(e.target.value)}><option>Any duration</option>{['3 Days','4 Days','5 Days','6 Days','7 Days','8 Days','9 Days','10 Days','11 Days','12 Days'].map(x=><option key={x}>{x}</option>)}</select></label><div><Search/><b>{visible.length}</b><span>Curated journeys</span></div></div></section><section id="package-collection" className="package-collections wrap"><div className="package-section-head"><p>Explore by devotion</p><h2>Pilgrimage collections,<br/>considered differently.</h2></div>{place!=='All Places'||duration!=='Any duration'?<div className="package-editorial-grid">{visible.map((p,i)=><LuxuryPackageCard p={p} index={i} key={p[0]}/>)}</div>:collections.map(([title,text,items],i)=><div className={`package-collection package-collection-${i}`} key={title as string}><header><span>0{i+1}</span><div><h3>{title as string}</h3><p>{text as string}</p></div></header><div>{(items as string[][]).map((p,j)=><LuxuryPackageCard p={p} index={j} key={p[0]}/>)}</div></div>)}{!visible.length&&<div className="empty">No package matches this combination. Our experts can create a custom journey.</div>}</section><section className="package-experience"><div className="wrap"><div className="package-section-head"><p>From enquiry to blessings</p><h2>A journey held with care</h2></div><div className="experience-path">{[['01','Listen','Your pace and preferences'],['02','Prepare','Stays, routes and guidance'],['03','Travel','Supported throughout'],['04','Darshan','Time for what matters'],['05','Return','Memories carried home']].map(([n,a,b],i)=><motion.article initial={{opacity:0,y:25}} whileInView={{opacity:1,y:0}} viewport={{once:false}} transition={{delay:i*.08}} key={a}><b>{n}</b><span/><h3>{a}</h3><p>{b}</p></motion.article>)}</div></div></section><section className="package-testimonials wrap"><div><p>Guest reflections</p><h2>Journeys remembered for their care.</h2><span>Thoughtful planning becomes most meaningful in the quiet moments our pilgrims carry home.</span></div>{[['Padmarao Parimala','Char Dham pilgrimage','Every transfer and stay was handled patiently. We could focus completely on the yatra.'],['Sai Swetha','Family temple tour','The route was comfortable for our parents and the team remained available throughout.'],['Santosh Satuluri','South India journey','Clear communication, well-planned hotels and warm support made the experience memorable.']].map(([n,j,q],i)=><motion.blockquote initial={{opacity:0,y:30}} whileInView={{opacity:1,y:0}} viewport={{once:false}} transition={{delay:i*.1}} key={n}><span>★★★★★ · Google review</span><p>“{q}”</p><footer><b>{n}</b><small>{j}</small></footer></motion.blockquote>)}</section><section className="package-final-cta"><img src={img.temple}/><div><p>Made around your faith, pace and comfort</p><h2>Begin Your Sacred Journey</h2><div><Button href={tel}>Talk to expert</Button><Button href={wa} outline>Request custom package</Button></div></div></section><Footer/></>
}

function LuxuryPackageCard({p,index}:{p:string[];index:number}){return <motion.article className="luxury-package-card" initial={{opacity:0,y:40}} whileInView={{opacity:1,y:0}} viewport={{once:false,amount:.2}} transition={{delay:(index%3)*.08,duration:.65}}><a href={`#package/${slug(p[0])}`} className="luxury-package-image"><img loading="lazy" src={p[4]} alt={p[0]}/><span>{p[2]}</span></a><div><small><MapPin/>{p[1]}</small><h3>{p[0]}</h3><dl><div><dt>Best season</dt><dd>October – March</dd></div><div><dt>Difficulty</dt><dd>{/Dham|Kedarnath/.test(p[0])?'Moderate':'Comfortable'}</dd></div></dl><footer><div><span>From</span><strong>₹{p[3]}</strong></div><a href={`#package/${slug(p[0])}`}>View itinerary <ArrowRight/></a><a href={wa}>Book now</a></footer></div></motion.article>}
function GuidePage() {
  const categories=[['Temple Guides','History, timings and sacred traditions',img.temple],['Festivals','Sacred celebrations across India',img.water],['Travel Tips','Thoughtful advice for peaceful journeys',img.chardham],['Darshan Guide','Temple entry, seva and aarti guidance',img.tirupati],['Accommodation','Trusted stays near sacred places',img.shirdi],['Packing Guide','Prepare comfortably for every climate',img.vaishno]]
  const tips=[['Packing','Carry light layers, medicines, identity documents and respectful temple clothing.'],['Accommodation','Choose verified stays with easy access to the temple and transport points.'],['Health','Allow time to acclimatize, remain hydrated and disclose mobility requirements early.'],['Temple Etiquette','Follow photography, queue, footwear and offering rules at every sacred site.'],['Dress Code','Prefer modest, comfortable clothing suitable for local customs and weather.'],['Weather','Review seasonal conditions and keep flexible time for mountain or monsoon routes.']]
  const [tip,setTip]=useState(0),[search,setSearch]=useState('')
  const guides=posts.filter(p=>p[0].toLowerCase().includes(search.toLowerCase())||p[1].toLowerCase().includes(search.toLowerCase()))
  return <><section className="guide-hero"><div className="guide-hero-bg"/><div className="guide-fog"/><div className="wrap guide-hero-content"><motion.p initial={{opacity:0,y:15}} animate={{opacity:1,y:0}}>The sacred knowledge collection</motion.p><motion.h1 initial={{opacity:0,y:35}} animate={{opacity:1,y:0}} transition={{duration:.8}}>Your Complete<em>Pilgrimage Guide</em></motion.h1><motion.span initial={{opacity:0}} animate={{opacity:1}} transition={{delay:.3}}>Everything you need to plan a safe, comfortable and spiritually enriching journey through India's most sacred places.</motion.span><motion.div className="guide-hero-actions" initial={{opacity:0,y:15}} animate={{opacity:1,y:0}} transition={{delay:.45}}><Button href="#guide-library">Explore guides</Button><Button href={wa} outline>Plan my journey</Button></motion.div><div className="guide-trust"><b>200+<small>Destinations</small></b><b>50,000+<small>Pilgrims</small></b><b>24×7<small>Expert guidance</small></b></div></div><a className="guide-scroll" href="#guide-search"><span/>Scroll to discover</a></section><section id="guide-search" className="guide-search-panel wrap"><Search/><input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search temples, festivals or destinations" aria-label="Search pilgrimage guides"/><div>{['Temple','Festival','Destination','Travel Tips'].map(x=><button onClick={()=>setSearch(x==='Travel Tips'?'Travel':x)} key={x}>{x}</button>)}</div></section><section className="guide-categories wrap"><div className="guide-section-head"><p>Explore the library</p><h2>Knowledge for every sacred journey</h2></div><div>{categories.map(([name,text,pic],i)=><motion.a href="#guide-library" className="guide-cover" initial={{opacity:0,y:35}} whileInView={{opacity:1,y:0}} viewport={{once:false,amount:.2}} transition={{delay:(i%3)*.08}} key={name}><img loading="lazy" src={pic}/><div><Sparkles/><h3>{name}</h3><p>{text}</p><ArrowRight/></div></motion.a>)}</div></section><section className="featured-guide wrap"><motion.img loading="lazy" src={img.chardham} initial={{scale:1.1}} whileInView={{scale:1}} viewport={{once:false}} transition={{duration:1}}/><div><span>Featured guide</span><p>Travel Guide · 8 min read · Kakani Editorial</p><h2>Char Dham: a considered guide to the four sacred shrines</h2><b>Route planning, registration, weather, health and darshan guidance for a meaningful Himalayan pilgrimage.</b><a href="#guide-library">Read guide <ArrowRight/></a></div></section><section id="guide-library" className="guide-library wrap"><div className="guide-section-head"><p>Recently published</p><h2>Stories, rituals and practical wisdom</h2></div><div className="guide-editorial-grid">{guides.slice(0,7).map((p,i)=><motion.article className={`guide-story story-${i}`} initial={{opacity:0,y:30}} whileInView={{opacity:1,y:0}} viewport={{once:false,amount:.2}} key={p[0]}><img loading="lazy" src={p[3]}/><div><span>{p[1]} · {i+4} min read</span><h3>{p[0]}</h3><p>Verified insights and thoughtful guidance for a well-prepared spiritual journey.</p><a>Read guide <ArrowRight/></a></div></motion.article>)}</div></section><section className="guide-destination-section"><div className="wrap guide-section-head"><p>Sacred places</p><h2>Plan by destination</h2></div><div className="guide-destination-rail">{destinationData.map(d=><a href={`#destination/${slug(d.name)}`} key={d.name}><img loading="lazy" src={d.image}/><div><span>{d.region}</span><h3>{d.name}</h3><p>{d.best} · {d.duration}</p><b>Explore <ArrowRight/></b></div></a>)}</div></section><section className="planner-zone wrap"><aside className="glass-planner"><p>Your journey, clearly planned</p><h2>Sacred Journey Planner</h2>{['Choose your destination','Select a comfortable season','Plan travel and stays','Review darshan guidance','Receive expert assistance'].map((x,i)=><div key={x}><span>{i+1}</span><p>{x}</p></div>)}<Button href={wa}>Plan with an expert</Button></aside><div className="travel-tips"><div className="guide-section-head"><p>Essential preparation</p><h2>Travel well. Arrive with peace.</h2></div>{tips.map(([name,text],i)=><article className={tip===i?'active':''} key={name}><button onClick={()=>setTip(i)}><span>0{i+1}</span>{name}<ChevronRight/></button><AnimatePresence>{tip===i&&<motion.p initial={{height:0,opacity:0}} animate={{height:'auto',opacity:1}} exit={{height:0,opacity:0}}>{text}</motion.p>}</AnimatePresence></article>)}</div></section><section className="guide-trust-story"><div><img loading="lazy" src={img.temple}/></div><div><p>Guidance you can trust</p><h2>Written with experience. Verified with care.</h2><span>Our pilgrimage knowledge combines experienced tour planning, destination research and practical information gathered around sacred routes.</span><div><b>50K+<small>Pilgrims guided</small></b><b>200+<small>Sacred places</small></b><b>24×7<small>Human support</small></b></div></div></section><section className="guide-newsletter wrap"><img loading="lazy" src={img.water}/><div><p>Letters from sacred India</p><h2>Receive thoughtful journey notes.</h2><div><input placeholder="Your email address" aria-label="Email address"/><button>Subscribe <ArrowRight/></button></div></div></section><section className="guide-closing"><div><h2>Begin Your Sacred Journey</h2><p>Let experienced hands shape a pilgrimage made for your pace, comfort and purpose.</p><div><Button href={tel}>Talk to expert</Button><Button href="#tour-packages" outline>Explore packages</Button></div></div></section><Footer/></>
}
