function BlogGrid({ small=false }: { small?: boolean }) { return <div className={small?'blog-grid small':'blog-grid'}>{posts.map(([title,cat,date,pic],i)=><motion.article className="blog-card guide-reveal" initial={{opacity:0,y:34,scale:.97}} whileInView={{opacity:1,y:0,scale:1}} viewport={{once:false,amount:.2,margin:'-25px 0px'}} transition={{duration:.55,delay:(i%4)*.06,ease:[.22,1,.36,1]}} whileHover={{y:-9}} key={title}><div className="guide-image"><img loading="lazy" src={pic} alt={title}/><i/></div><span>{cat}</span><div className="date">{date}</div><h3>{title}</h3><p>Helpful insights, route details and spiritual guidance for a meaningful journey.</p><a>Read More <ArrowRight size={13}/></a></motion.article>)}</div> }
